"use client";

import { useState } from "react";
import { joinWaitlist } from "./actions";

export default function Home() {
  const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");
  const [message, setMessage] = useState("");

  async function handleSubmit(formData: FormData) {
    setStatus("loading");
    const result = await joinWaitlist(formData);

    if (result?.success) {
      setStatus("success");
      setMessage("You're on the list! We'll be in touch soon.");
    } else if (result?.error) {
      setStatus("error");
      setMessage(result.error);
    }
  }

  return (
    <main className="relative min-h-screen flex items-center justify-center bg-[#f6f7f9] px-4 sm:px-6 overflow-hidden">
      {/* Soft Top Glow */}
      <div className="absolute top-[-150px] left-1/2 -translate-x-1/2 w-[600px] sm:w-[800px] h-[300px] sm:h-[400px] bg-blue-500/20 blur-[120px] opacity-40 pointer-events-none" />

      <section className="relative z-10 w-full max-w-xl sm:max-w-2xl text-center flex flex-col items-center justify-center">
        {/* Badge */}
        <div className="mb-6 flex items-center gap-2 w-fit rounded-full border border-gray-200 bg-white px-3 sm:px-4 py-1 text-[10px] sm:text-[11px] font-semibold tracking-wide text-blue-600 shadow-sm">
          <span className="h-2 w-2 rounded-full bg-blue-500 animate-pulse" />
          Early Access Open
        </div>

        {/* Headline */}
        <h1 className="text-4xl sm:text-6xl lg:text-7xl font-extrabold tracking-tight text-gray-900 leading-tight sm:leading-[1.05] mb-5">
          Build.
          <br />
          <span className="bg-gradient-to-b from-blue-500 to-blue-600 bg-clip-text text-transparent">
            Unstoppable.
          </span>
        </h1>

        {/* Subtext */}
        <p className="max-w-md sm:max-w-lg text-gray-500 text-base sm:text-lg leading-relaxed mb-8">
          The boilerplate for the 1%. Ship your SaaS in 24 hours
          with our battle-tested Next.js + Supabase stack.
        </p>

        {/* Form */}
        <div className="w-full max-w-md">
          {status === "success" ? (
            <div className="rounded-2xl border border-green-200 bg-green-50 px-6 py-4 text-sm font-medium text-green-700 shadow-sm">
              🎉 {message}
            </div>
          ) : (
            <form
              action={handleSubmit}
              className="flex flex-col sm:flex-row items-stretch gap-2 rounded-2xl border-[1.5px] border-slate-300 bg-white p-1.5 shadow-[0_2px_16px_rgba(37,99,235,0.12),0_1px_4px_rgba(0,0,0,0.06)]"
            >
              <input
                name="email"
                type="email"
                required
                placeholder="dev@twitter.com"
                className="flex-1 h-11 px-4 text-sm text-gray-800 placeholder-gray-400 bg-transparent outline-none"
              />
              <button
                type="submit"
                disabled={status === "loading"}
                className="h-11 px-6 rounded-xl bg-gradient-to-br from-blue-500 to-blue-700 text-white text-sm font-bold tracking-wide shadow-[0_2px_10px_rgba(37,99,235,0.4)] hover:shadow-[0_4px_18px_rgba(37,99,235,0.5)] hover:-translate-y-px active:scale-95 transition-all duration-150 disabled:opacity-60 disabled:cursor-not-allowed"
              >
                {status === "loading" ? "Joining..." : "✦ Claim Spot"}
              </button>
            </form>
          )}

          {/* Error message */}
          {status === "error" && (
            <p className="mt-3 text-sm text-red-500 text-center">{message}</p>
          )}
        </div>

        {/* Social Proof */}
        <div className="mt-8 flex flex-col items-center gap-3">
          <div className="flex -space-x-2.5">
            {[1, 2, 3, 4].map((i) => (
              <img
                key={i}
                src={`https://i.pravatar.cc/100?u=${i}`}
                className="h-8 w-8 sm:h-9 sm:w-9 rounded-full border-[2.5px] border-indigo-100 outline outline-[1.5px] outline-blue-200 shadow-sm bg-gray-200"
                alt="user"
              />
            ))}
          </div>
          <p className="text-xs sm:text-sm text-gray-500">
            Joined by{" "}
            <span className="font-semibold text-gray-900">2.4k builders</span>
          </p>
        </div>
      </section>
    </main>
  );
}